const loyaltyDiscountFor = (customer: Customer, basePremium: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
    ? basePremium * LOYALTY_DISCOUNT_RATE
    : 0;

const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;

const followupDiscountFor = (stepIndex: number, basePremium: number): number =>
  isFollowupContract(stepIndex)
    ? basePremium * FOLLOWUP_DISCOUNT_RATE
    : 0;

const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
  const basePremium = sumBasePremiums(items);
  const surcharges = itemSurcharges(items);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const loyaltyDiscount = loyaltyDiscountFor(customer, basePremium);
  const followupDiscount = followupDiscountFor(stepIndex, basePremium);
  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
};
